window.APP_BANK = [{"id":"web-b1-1","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"下列有關商業智慧及營運智慧的敘述何者有誤？","options":{"A":"商業智慧可運用一系列的分析工具","B":"營運智慧是將商業智慧應用在企業營運模式中的動態系統","C":"商業智慧分析無法提升組織競爭優勢","D":"營運智慧將有助於改善企業營運績效"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"商業智慧透過分析工具將資料轉化為決策洞察，正是提升組織競爭優勢的重要手段，因此選項C「無法提升組織競爭優勢」的敘述有誤。A、B、D皆為正確描述：BI可運用一系列分析工具，OI是BI應用於企業營運模式的動態系統，且有助於改善營運績效。","concept":"商業智慧與營運智慧的關係","aiExplained":true},{"id":"web-b1-2","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"下列何者不是平衡計分卡的構面？","options":{"A":"顧客","B":"員工","C":"財務","D":"內部流程"},"answer":"B","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"平衡計分卡（BSC）的四大構面為財務、顧客、內部流程、學習與成長。「員工」並非四大構面之一，故選B。","concept":"平衡計分卡四構面","aiExplained":true},{"id":"web-b1-3","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"商業智慧（Business Intelligent）分析工具正逐漸變得越來越強大，用起來也更友善，其中何種運用可讓分析結果更快顯現？","options":{"A":"記憶體內運算（in-memory computing）","B":"資料倉儲","C":"Hadoop NoSQL","D":"資料探勘"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"記憶體內運算將資料直接放在記憶體中處理，省去磁碟存取的I/O延遲，因此能讓分析結果更快顯現。資料倉儲、Hadoop NoSQL與資料探勘屬於資料儲存或分析技術，重點不在即時加速運算。","concept":"記憶體內運算（in-memory computing）","aiExplained":true},{"id":"web-b1-4","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"下列何者為一種用於分析非結構化文字的的技法，它會檢查關鍵字、語意結構、 語言上的關係、口語片段、常用語詞、帶有情感的文字和其他的特徵來汲取有意義的商業智慧？","options":{"A":"商業智慧","B":"文字探勘","C":"網站探勘","D":"資料探勘"},"answer":"B","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"文字探勘（Text Mining）專門分析非結構化文字，透過關鍵字、語意結構、語言關係與情感字詞等特徵汲取有意義的資訊。資料探勘主要處理結構化資料，網站探勘則針對網站內容與使用行為，皆不符題意。","concept":"文字探勘","aiExplained":true},{"id":"web-b1-5","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"決策支援系統含有一些工具，可幫助管理模擬活動事件，進而預測未來，下列哪一種工具可用來建立多種變數之間的關係模型，使用者可變更一些變數，看其他變數如何受影響？","options":{"A":"目標搜尋","B":"最佳化","C":"預測","D":"假設分析"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"假設分析（What-if Analysis）建立多變數間的關係模型，使用者變更某些變數即可觀察其他變數如何受影響，符合題意。目標搜尋是反向由目標值推算輸入值，最佳化是求最佳解，預測是以歷史資料推估未來，皆與題幹描述不符。","concept":"假設分析（What-if Analysis）","aiExplained":true},{"id":"web-b1-6","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"下列何者為一種決策支援工具，通常是建立在Excel 模型上，使用者設定某個特定變數的目標值，然後告訴程式改變哪個變數以嘗試達到目標？","options":{"A":"假設分析","B":"目標搜尋","C":"最佳化","D":"預測"},"answer":"B","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"目標搜尋（Goal Seeking）常建立在Excel模型上，由使用者先設定目標值，程式再反推需改變哪個變數才能達成該目標，故選B。假設分析則是正向改變變數觀察結果，方向相反。","concept":"目標搜尋（Goal Seeking）","aiExplained":true},{"id":"web-b1-7","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"下列何者為一種統計型的決策支援工具，用來分析歷史趨勢和其他商業智慧以了解我們關心的某些變數？","options":{"A":"目標搜尋","B":"假設分析","C":"預測","D":"最佳化"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"預測（Forecasting）是統計型的決策支援工具，透過分析歷史趨勢與其他商業智慧資訊，推估所關心變數的未來走向，故選C。目標搜尋、假設分析與最佳化都不是以統計分析歷史趨勢為核心。","concept":"預測（Forecasting）","aiExplained":true},{"id":"web-b1-8","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"下列何者為一種資料分析處理軟體，允許使用者深入探究資料，或將資料倉儲內的龐大資料予以切細分塊，以便揭露出隱藏的模式或趨勢？","options":{"A":"統計與模型技術","B":"商業智慧","C":"On-Line Transaction Processing（OLTP）","D":"線上分析處理"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"線上分析處理（OLAP）允許使用者對資料倉儲中的龐大資料進行切片、切塊（slice and dice）與下鑽等多維度分析，以揭露隱藏的模式或趨勢，故選D。OLTP是處理日常交易的系統，不做多維分析。","concept":"線上分析處理（OLAP）","aiExplained":true},{"id":"web-b1-9","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"統計學上的各種關聯性對於我們有用處，哪一種分析的技法是為了尋找這樣的關聯性？","options":{"A":"購物籃分析","B":"線上分析處理","C":"假設分析","D":"最佳化"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"購物籃分析（Market Basket Analysis）是為了尋找項目之間統計關聯性的技法，例如找出哪些商品經常被同時購買，故選A。OLAP著重多維查詢、假設分析與最佳化則用於模擬與求解，皆非以尋找關聯性為目的。","concept":"購物籃分析（關聯分析）","aiExplained":true},{"id":"web-b1-10","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"下列哪種系統可以協助企業瞭解並管理產品的詳細狀況？","options":{"A":"供應鏈管理系統","B":"顧客關係管理系統","C":"產品生命週期管理系統","D":"會計資訊系統"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"產品生命週期管理（PLM）系統管理產品從設計、開發、生產到退役各階段的完整資訊，可協助企業瞭解並管理產品的詳細狀況，故選C。SCM管理供應鏈流程、CRM管理顧客關係、會計資訊系統處理財務帳務，皆非以產品資訊為核心。","concept":"產品生命週期管理（PLM）","aiExplained":true},{"id":"web-b1-11","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"下列何者不是企業導入ERP 系統的財務與會計模組的效用？","options":{"A":"簡化會計處理程序","B":"進行更精細的財務分析","C":"即時提供財務分析資訊","D":"自動提供財務問題的解決方法"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"ERP財務與會計模組能簡化會計處理程序、進行更精細的財務分析並即時提供財務資訊，但它只是提供資訊與分析的工具，無法自動提供財務問題的解決方法，決策仍須由人判斷，故選D。","concept":"ERP 財務會計模組效用","aiExplained":true},{"id":"web-b1-12","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"「雖然企業有營運智慧（Operations Intelligence, OI）人員分析，但公司主管依舊憑藉直覺來做決策」，這是企業中甚麼因素造成的？","options":{"A":"流程因素","B":"制度化因素","C":"組織文化因素","D":"資料因素"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"企業已有OI人員與分析結果，但主管仍憑直覺決策，代表組織缺乏「以資料為依據做決策」的文化，屬於組織文化因素，故選C。這不是流程、制度或資料本身的問題，而是決策習慣與價值觀所致。","concept":"資料驅動決策與組織文化","aiExplained":true},{"id":"web-b1-13","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"下列對於營運智慧（Operations Intelligence, OI）的敘述何者有誤？","options":{"A":"提供更主動和預先分析給管理階層","B":"著重於管理小規模的營運事件","C":"使用語意式搜尋，把人和技術連接起來","D":"協助企業進行IT 資訊連貫與一致的規劃和執行"},"answer":"B","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"營運智慧著重於即時監控與管理大規模的營運事件與資料流，而非小規模事件，故B的敘述有誤。A、C、D皆為OI的正確特性：提供主動與預先的分析、以語意式搜尋連結人與技術、協助IT資訊連貫一致的規劃與執行。","concept":"營運智慧（OI）特性","aiExplained":true},{"id":"web-b1-14","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"提高製成品的良率是商業智慧應用於生產管理的主要目的之一，請問正確的良率計算方式為何？","options":{"A":"「實際確認數量」除以「所發放工單數量」","B":"「實際確認數量」除以「生產數量」","C":"「未報廢數量」除以「實際確認數量」","D":"「所發放工單數量」除以「生產數量」"},"answer":"B","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"良率反映實際產出的合格品占總生產量的比例，計算方式為「實際確認數量」除以「生產數量」，故選B。以工單發放數量或報廢數量作為分母、分子的算法均不符合良率的定義。","concept":"良率計算","aiExplained":true},{"id":"web-b1-15","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"下列何者非雲端顧客關係管理（Customer Relationship Management, CRM）系統的特性？","options":{"A":"透過網頁登入，存取權限預先由系統管理人員設定","B":"員工可以透過不同設備登入","C":"提供使用者在手機或平板登入行動App","D":"先購買一套CRM 來使用"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"雲端CRM採訂閱式服務，使用者透過網頁或行動App登入即可使用，不需要先買斷一套軟體安裝在自家機房，故「先購買一套CRM來使用」不是雲端CRM的特性，選D。A、B、C皆為雲端CRM常見特性。","concept":"雲端CRM特性","aiExplained":true},{"id":"web-b1-16","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"企業營運計畫中最主要的是？","options":{"A":"行銷部分","B":"營運部分","C":"財務部分","D":"如何串聯以上各個部分"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"企業營運計畫包含行銷、營運、財務等各個部分，單一部分再完善也無法獨立運作，最關鍵的是如何將各部分串聯整合成一致可行的整體計畫，故選D。","concept":"企業營運計畫整合","aiExplained":true},{"id":"web-b1-17","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"下列何者不是營運智慧（Operations Intelligence, OI）對組織的成效？","options":{"A":"協助企業開發新客源","B":"提升企業整體績效","C":"提升員工個人在統計方面的專業知識","D":"減少營運成本"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"OI對組織的成效體現在營運層面：協助開發新客源、提升整體績效、減少營運成本。提升員工「個人」的統計專業知識屬於個人能力培養，並非OI對組織的成效，故選C。","concept":"營運智慧的組織成效","aiExplained":true},{"id":"web-b1-18","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"電子商務蓬勃發展，相關技術與服務亦推陳出新，下列敘述何者有誤？","options":{"A":"可用來分析消費者行為的大數據分析，其四大特徵為數量（Volume）、速度（Velocity）、多樣性（Variety）和可見性（Visibility）","B":"目前虛擬貨幣的比特幣是採用區塊鏈的技術","C":"數位時代可透過應用程式介面（Application Programming Interface, API） 的連接，進行跨產業的產品和服務，提供完整的一站式服務","D":"透過電子數據交換（Electronic Data Interchange, EDI），可使兩個企業組織之間進行標準化交易"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"大數據的四大特徵為數量（Volume）、速度（Velocity）、多樣性（Variety）與真實性（Veracity），選項A將第四項誤寫為可見性（Visibility），故有誤。B、C、D關於比特幣採用區塊鏈、API串接一站式服務、EDI標準化企業間交易的敘述皆正確。","concept":"大數據4V特徵","aiExplained":true},{"id":"web-b1-19","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"建置資料倉儲系統需要規劃與設計流程，該流程包括以下四個步驟，請問它們的順序為何？（1）系統建置；（2）架構設計；（3）測試與發布；（4）需求與現況。","options":{"A":"1243","B":"4213","C":"1342","D":"4123"},"answer":"B","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"資料倉儲建置流程應先進行需求與現況分析（4），再做架構設計（2），接著系統建置（1），最後測試與發布（3），順序為4213，故選B。此順序符合一般系統開發生命週期：先分析、後設計、再建置、最後測試上線。","concept":"資料倉儲建置流程","aiExplained":true},{"id":"web-b1-20","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"下列何者為營運智慧系統架構的子系統？","options":{"A":"資料倉儲系統","B":"資料分析系統","C":"資料呈現系統","D":"以上皆是"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"營運智慧系統架構包含資料倉儲系統（儲存整合資料）、資料分析系統（進行分析運算）與資料呈現系統（將結果視覺化呈現）三個子系統，三者皆屬其架構，故選D。","concept":"營運智慧系統架構","aiExplained":true},{"id":"web-b1-21","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"下列何者是企業組織為了能更系統化管理智慧資本而採用的一系列策略及實務做法？","options":{"A":"資訊管理","B":"知識管理","C":"資料庫管理","D":"線上交易處理"},"answer":"B","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"知識管理（Knowledge Management）是企業為系統化管理智慧資本（知識資產）所採用的一系列策略與實務做法，涵蓋知識的創造、儲存、分享與應用，故選B。資訊管理與資料庫管理處理的是資訊與資料層次，並非智慧資本。","concept":"知識管理","aiExplained":true},{"id":"web-b1-22","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"下列何者是模仿人類專家推理或決策的一種方法，它汲取自某個藉由專家的協助而建立起來的特定領域的知識庫？","options":{"A":"專家系統","B":"神經網路","C":"模擬","D":"預測"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"專家系統（Expert System）由專家協助建立特定領域的知識庫，再透過推論引擎模仿人類專家的推理與決策，故選A。神經網路是從大量資料中自行學習模式，不依賴專家建立的知識庫。","concept":"專家系統","aiExplained":true},{"id":"web-b1-23","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"下列何者是可阻絕大部分軟體機器人的一種方法，亦稱作驗證碼或人機驗證， 造訪者必須先通過這樣的測驗才能進行註冊或進入網站？","options":{"A":"Completely Automated Public Turing test to tell Computers and Humans Apart （CAPTCHA）","B":"語音辨識","C":"指紋辨識","D":"虹膜辨識"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"CAPTCHA（全自動區分電腦與人類的公開圖靈測試）即俗稱的驗證碼或人機驗證，用來阻絕軟體機器人自動註冊或進入網站，故選A。語音、指紋、虹膜辨識屬於生物特徵身分辨識技術，用途不同。","concept":"CAPTCHA 人機驗證","aiExplained":true},{"id":"web-b1-24","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"企業資料倉儲特點不包括？","options":{"A":"完整企業資料需求","B":"連結多重功能性領域","C":"去中心化管理","D":"高度資料標準化"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"企業資料倉儲（EDW）是將全企業資料集中整合、統一管理的系統，特點包括滿足完整企業資料需求、連結多重功能領域與高度資料標準化。「去中心化管理」與其集中式的本質相反，故選C。","concept":"企業資料倉儲特點","aiExplained":true},{"id":"web-b1-25","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"從過去決策而來的資料進行挖掘所得的問題，從中萃取出可增進未來決策過程精確度的少數規則與模式稱為？","options":{"A":"監督式學習","B":"探索分析","C":"群集分析","D":"關連規則"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"監督式學習利用過去已知結果（標籤）的決策資料進行訓練，萃取出規則與模式，以提高對未來案例判斷的精確度，符合題意，故選A。探索分析與群集分析屬於非監督式方法，沒有以過去決策結果作為學習依據。","concept":"監督式學習","aiExplained":true},{"id":"web-b1-26","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"下列何者是將在網站上從事廣告和電子商務而完成某些活動的訪客數，除以訪客總人數的比率稱之為？","options":{"A":"CTR（Click through rate）","B":"CPC（Cost-per -Click）","C":"CPM（Cost Per 1000 impression）","D":"Conversion rate"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"轉換率（Conversion Rate）是完成特定活動（如購買、註冊）的訪客數除以訪客總人數的比率，故選D。CTR是廣告點擊次數除以曝光次數的點擊率，CPC與CPM則是廣告計價方式，不是比率指標的定義。","concept":"轉換率（Conversion Rate）","aiExplained":true},{"id":"web-b1-27","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"訪客每一次點擊廣告進入廣告主網站，廣告主需要花費的金額，是指下列何種電子商務指標？","options":{"A":"CPC（Cost-per-Click）","B":"CTR（Click through rate）","C":"CPM（Cost Per 1000 impression）","D":"Conversion rate"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"CPC（Cost-per-Click，每次點擊成本）是訪客每點擊一次廣告，廣告主需支付的金額，故選A。CPM是每千次曝光成本，CTR是點擊率，Conversion rate是轉換率，皆與「每次點擊付費」的定義不符。","concept":"CPC 每次點擊成本","aiExplained":true},{"id":"web-b1-28","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"下列何者不是價值鏈中的主要活動？","options":{"A":"生產作業","B":"進貨物流","C":"售後服務","D":"人力資源管理"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"波特價值鏈的主要活動為進貨物流、生產作業、出貨物流、行銷與銷售、售後服務；人力資源管理屬於支援活動（與採購、技術發展、企業基礎設施同類），故選D。","concept":"價值鏈主要活動與支援活動","aiExplained":true},{"id":"web-b1-29","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"下列何者不是電子採購（E-procurement）模式帶給企業的價值？","options":{"A":"降低成本","B":"增加文件作業","C":"加速採購","D":"整合供應鏈"},"answer":"B","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"電子採購透過電子化流程降低成本、加速採購並整合供應鏈，其效益之一正是「減少」紙本文件作業；「增加文件作業」與電子採購的價值相反，故選B。","concept":"電子採購效益","aiExplained":true},{"id":"web-b1-30","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"「任何企業對顧客都有存在的價值，這個價值決定顧客的期望」，此敘述是屬於顧客關係管理策略發展循環「PEPSI」模式的哪一步驟？","options":{"A":"企業的定位和價值主張","B":"了解顧客的經驗","C":"選擇最適流程","D":"歸類"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"題幹強調「企業對顧客存在的價值決定顧客的期望」，談的是企業如何定位自身並提出價值主張，對應PEPSI模式中的「企業的定位和價值主張（Positioning）」步驟，故選A。了解顧客經驗、選擇最適流程與歸類屬於後續步驟。","concept":"CRM之PEPSI模式","aiExplained":true},{"id":"web-b1-31","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"企業績效評估是個複雜且需要大量資料分析的過程，下列關於企業績效評估之敘述，何者正確？","options":{"A":"只需要評估由電腦運算出來的量化資料","B":"只需要評估由訪談資料得到的質化資料","C":"量化與質化資料都應收集並納入考量","D":"量化資料的重要性大於質化資料"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"企業績效評估應同時收集量化資料（如財務數據、營運指標）與質化資料（如訪談意見、顧客回饋），兩者互補並皆納入考量，故選C。只採單一類型或斷言量化必定重於質化，都會造成評估偏頗。","concept":"企業績效評估（量化與質化）","aiExplained":true},{"id":"web-b1-32","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"下列何者不是價值鏈管理的重要利益？","options":{"A":"改善採購","B":"改變顧客群","C":"改善產品發展","D":"增進顧客訂單管理"},"answer":"B","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"價值鏈管理的利益在於改善鏈上各項活動的效率與效果，如改善採購、改善產品發展、增進顧客訂單管理等；「改變顧客群」是市場策略層面的調整，並非價值鏈管理的重要利益，故選B。","concept":"價值鏈管理效益","aiExplained":true},{"id":"web-b1-33","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"下列有關大數據行銷的描述，何者有誤？","options":{"A":"可更精準預測和掌握消費者購買行為","B":"目的是為了達到一對一行銷","C":"消費者自加入會員起留下的每一筆交易紀錄都同等重要","D":"大數據必須先整理成結構化與數值化的資料架構，才能有效率地進行數據分析"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"大數據行銷中，資料的價值會隨時間遞減，近期的消費行為通常比久遠的紀錄更能反映顧客當前偏好，並非每筆交易紀錄同等重要，故C有誤。A、B、D皆為正確描述：大數據可精準預測購買行為、目標是一對一行銷，且需先整理成結構化與數值化架構才能有效分析。","concept":"大數據行銷","aiExplained":true},{"id":"web-b1-34","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"下列哪一項不是人力資源績效指標的特性？","options":{"A":"在科學上未必具備良好的精確性","B":"是一個量化的數字","C":"其適用性是暫時的","D":"反應特定層面的現象"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"指標的典型特性包括：是一個量化的數字、在科學上未必具備良好的精確性、適用性是暫時的，且反映的是整體或一般層面的現象。因此「反應特定層面的現象」並非指標的特性，D 為正確選項。","concept":"績效指標特性","aiExplained":true},{"id":"web-b1-35","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"企業使用大數據分析後，下列何者不是目前的網路行銷的趨勢？","options":{"A":"價格彈性化","B":"配銷科層化","C":"產品客製化","D":"行銷互動化"},"answer":"B","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"大數據分析下的網路行銷趨勢是價格彈性化（動態定價）、產品客製化與行銷互動化，配銷通路則走向去中間化、扁平化。「配銷科層化」代表層層中間商的階層式通路，與趨勢相反，故 B 不是趨勢。","concept":"大數據行銷趨勢","aiExplained":true},{"id":"web-b1-36","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"在顧客關係管理（Customer Relationship Management, CRM）中，資料探勘是屬於？","options":{"A":"操作CRM 的應用工具","B":"協同型CRM 的溝通平台","C":"分析型CRM 的核心技術","D":"客戶經驗管理的指標"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"CRM 分為操作型、協同型與分析型三類：操作型處理前端銷售與服務流程、協同型負責與客戶的溝通管道，而分析型 CRM 以資料倉儲與資料探勘為核心技術，從客戶資料中發掘行為模式與價值，故資料探勘屬分析型 CRM 的核心技術。","concept":"分析型CRM","aiExplained":true},{"id":"web-b1-37","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"營運智慧/商業智慧系統規劃階段中的企業基礎設施評估，可分為技術面與非技術面的評估。請問下列何者不是技術面的基礎設施評估項目？","options":{"A":"中介軟體平台","B":"網路安全平台","C":"硬體平台","D":"資料庫管理系統平台"},"answer":"B","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"BI 規劃階段的技術面基礎設施評估項目為硬體平台、中介軟體平台與資料庫管理系統平台三者；網路安全平台不在技術面基礎設施評估項目之列，故選 B。","concept":"BI 基礎設施評估","aiExplained":true},{"id":"web-b1-38","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"下列何種技術可用來進行營運智慧/商業智慧專案的規劃、排程與控制？","options":{"A":"甘特圖（Grant chart）","B":"計畫評核技術（PERT）","C":"要徑法（CPM）","D":"以上皆是"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"甘特圖、計畫評核技術（PERT）與要徑法（CPM）都是專案管理中用於規劃、排程與進度控制的經典技術，BI 專案同樣適用，故答案為以上皆是。","concept":"專案管理技術","aiExplained":true},{"id":"web-b1-39","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"下列何者是一個以網路為介面的系統，它能整合企業內部網路等科技，讓所有企業內部網路使用者及特定企業外部網路使用者，存取各種內部與外部企業應用與服務？","options":{"A":"企業資訊入口網站","B":"數位儀表板","C":"知識管理系統","D":"決策支援系統"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"企業資訊入口網站（EIP）以瀏覽器為單一入口，整合企業內部網路與外部應用服務，供內部員工及特定外部使用者存取，完全符合題述。數位儀表板僅視覺化呈現績效指標，知識管理系統與決策支援系統的定位也與題述不符。","concept":"企業資訊入口網站(EIP)","aiExplained":true},{"id":"web-b1-40","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"文件探勘與文件導向的搜尋是支援哪一種知識庫管理系統？","options":{"A":"結構化知識系統","B":"半結構化知識系統","C":"知識網絡系統","D":"非結構化知識系統"},"answer":"B","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"半結構化知識系統用來管理電子郵件、簡報、影音等未有完整結構的文件，因文件格式不一，需仰賴文件探勘與文件導向的搜尋技術來組織與尋找知識。結構化知識系統管理的是正式結構化文件，知識網絡系統則著重專家連結，皆與題述技術不符。","concept":"知識管理系統分類","aiExplained":true},{"id":"web-b1-41","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"Web 2.0 上的Wiki、Blog 都是在支援社群網路（Social Network）的聯絡與溝通，是屬於哪一種知識庫管理系統？","options":{"A":"結構化知識系統","B":"半結構化知識系統","C":"知識網路系統","D":"知識工作系統"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"知識網路系統著重人與人之間的連結，支援社群網路的聯絡與溝通、連結專家與需要知識的人，Wiki、Blog 等 Web 2.0 工具即屬此類。結構化與半結構化知識系統管理的是文件，知識工作系統則是給知識工作者創造知識用的專門工具。","concept":"知識網路系統","aiExplained":true},{"id":"web-b1-42","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"電腦輔助設計、虛擬實境系統是可用以支援知識管理的資訊科技，並支援知識工作者創造知識，屬於下列哪一類？","options":{"A":"支援組織整體的知識管理系統","B":"支援知識的獲取、發掘、儲存與執行","C":"支援知識工作者創造知識","D":"知識網絡系統"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"電腦輔助設計（CAD）與虛擬實境系統屬於知識工作系統，是提供給工程師、設計師等知識工作者創造新知識的專門工具，因此歸類為「支援知識工作者創造知識」。它們並非服務組織整體的知識管理系統，也不是連結專家的知識網絡系統。","concept":"知識工作系統","aiExplained":true},{"id":"web-b1-43","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"專家系統與類神經網路屬於哪種支援知識管理系統？","options":{"A":"智慧型系統","B":"知識工作者系統","C":"知識管理系統","D":"知識網路系統"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"專家系統與類神經網路屬於智慧型技術（智慧型系統），用於擷取、保存與應用專家知識或從資料中發掘知識模式。知識工作者系統指 CAD 等創造知識的工具，知識網路系統則是連結專家與使用者的系統，皆非本題所指。","concept":"智慧型技術","aiExplained":true},{"id":"web-b1-44","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c1","stem":"文件管理系統與搜尋引擎屬哪種知識管理系統？","options":{"A":"結構化知識系統","B":"半結構化知識系統","C":"知識網路系統","D":"智慧型技術"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"結構化知識系統管理正式、結構化的文件知識庫（如報告、簡報範本等正式文件），其核心功能即為文件管理系統搭配搜尋引擎，讓使用者能存放並檢索正式文件，故選 A。半結構化知識系統處理的是電子郵件等格式不一的內容。","concept":"結構化知識系統","aiExplained":true},{"id":"web-b1-45","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c2","stem":"假設有一組資料為某襯衫尺寸，分為特小、小、中、大、特大，請問此資料的特性屬於何種資料？","options":{"A":"名目資料","B":"次序資料","C":"等距資料","D":"比值資料"},"answer":"B","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"特小到特大的尺寸有明確的大小順序，但類別之間的間距不相等也無法計算差值，屬於次序（順序）資料。名目資料無順序之分，等距與比值資料則是數值型資料，皆不符合。","concept":"資料衡量尺度","aiExplained":true},{"id":"web-b1-46","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c2","stem":"資料倉儲是從結構化的資料來源建立，下列何者為不正統且不合適的資料來源？","options":{"A":"企業資源規劃系統（Enterprise resource planning, ERP）資料","B":"銷售點系統（Point of sale, POS）資料","C":"模擬資料","D":"Open Data 公開資料"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"資料倉儲應以真實營運產生的結構化資料為來源，如 ERP、POS 交易資料或可信的公開資料。模擬資料是人為產生、非真實發生的紀錄，用於資料倉儲會扭曲分析結果，屬不正統且不合適的來源。","concept":"資料倉儲資料來源","aiExplained":true},{"id":"web-b1-47","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c2","stem":"任何被記錄的事物都是資料，而資料的獲取可以有很多方式，下列何者較不建議採用？","options":{"A":"電話中所說的話","B":"書面報告的內容","C":"電子郵件的內容","D":"文件範例的內容"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"電話內容、書面報告與電子郵件都是實際發生、被記錄下來的事實，屬可用的資料來源；文件範例只是示範用的格式樣本，內容並非真實紀錄，作為資料來源會引入虛構資訊，故較不建議採用。","concept":"資料獲取來源","aiExplained":true},{"id":"web-b1-48","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c2","stem":"變數分為質變數和量變數，若某資料為學生體重，請問此變數為量變數的哪一類？","options":{"A":"連續變數","B":"離散變數","C":"順序變數","D":"以上皆非"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"體重可以在任一區間內取任意數值（例如 60.5 公斤、60.55 公斤），屬於量變數中的連續變數。離散變數只能取可數的數值（如人數），順序變數則屬質變數的範疇。","concept":"連續與離散變數","aiExplained":true},{"id":"web-b1-49","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c2","stem":"群集分析可以運用在各種具有大量數據的領域中，下列哪種不是群集分析的應用？","options":{"A":"產品組合","B":"市場區隔","C":"行銷策略","D":"信用評估"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"群集分析屬非監督式學習，常用於市場區隔、產品組合規劃與行銷策略等把相似對象分群的情境。信用評估需要以歷史違約與否的標籤建立預測模型，屬於監督式的分類問題，不是群集分析的典型應用。","concept":"群集分析應用","aiExplained":true},{"id":"web-b1-50","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c2","stem":"請問一般資料處理流程也就是ETL 作業流程的順序為何？","options":{"A":"資料蒐集、資料轉換、資料載入","B":"資料轉換、資料蒐集、資料載入","C":"資料蒐集、資料載入、資料轉換","D":"資料載入、資料轉換、資料蒐集"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"ETL 依序為 Extract（提取／蒐集）、Transform（轉換）、Load（載入）：先從來源系統蒐集資料，再進行清理與格式轉換，最後載入資料倉儲，故順序為資料蒐集、資料轉換、資料載入。","concept":"ETL 流程","aiExplained":true},{"id":"web-b1-51","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c2","stem":"有效的資料倉儲核心在於能自動加入高品質資料至資料倉儲中的流程，下列何者不包括此流程？","options":{"A":"提取（Extract）","B":"轉換（Transform）","C":"分析（Analyze）","D":"載入（Load）"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"將高品質資料自動加入資料倉儲的流程即 ETL，包含提取（Extract）、轉換（Transform）與載入（Load）三步驟。分析（Analyze）是資料進入倉儲之後的應用活動，不屬於 ETL 流程本身。","concept":"ETL 流程","aiExplained":true},{"id":"web-b1-52","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c2","stem":"若某公司依據業務需求將郵件地址資訊分為國家、省/縣（市）、城市、郵遞區號、街道和門牌號碼，請問此為資料轉換的哪一種？","options":{"A":"資料分群","B":"建立新變數","C":"轉換變數","D":"分解資料"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"把一個完整的地址欄位拆解成國家、縣市、郵遞區號、街道等多個欄位，是將單一欄位切分為多個組成部分，屬於資料轉換中的「分解資料」。建立新變數是衍生出原本不存在的欄位，轉換變數則是改變既有欄位的格式或尺度。","concept":"資料轉換-分解資料","aiExplained":true},{"id":"web-b1-53","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c2","stem":"資料倉儲建置過程中會對資料探勘的結果有很大的影響是屬於哪一階段？","options":{"A":"提取（Extract）","B":"轉換（Transform）","C":"分析（Analyze）","D":"載入（Load）"},"answer":"B","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"轉換（Transform）階段負責資料清理、格式統一、整併與衍生欄位，決定了進入資料倉儲的資料品質與內容形態，因此對後續資料探勘結果影響最大。提取與載入主要是搬移資料，影響相對較小。","concept":"ETL 轉換階段","aiExplained":true},{"id":"web-b1-54","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c2","stem":"通常採用ELT 流程將資料自動載入資料倉儲內應遵從哪一模式執行？","options":{"A":"週期性","B":"選擇性","C":"隨機性","D":"以上皆非"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"資料自動載入資料倉儲應依固定排程（如每日、每週、每月）週期性執行，才能維持資料更新的一致性與可預期性；若採選擇性或隨機性執行，資料的完整性與時效性將難以掌控。","concept":"資料載入模式","aiExplained":true},{"id":"web-b1-55","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c2","stem":"會進行資料轉換的主要原因，與下列哪種情況較無關？","options":{"A":"資料欄位定義不一致","B":"資料格式型態不同","C":"資料檔案太大","D":"資料不完整"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"資料轉換是為了解決來源系統間欄位定義不一致、格式型態不同以及資料不完整等品質與整合問題。資料檔案太大屬於儲存與運算效能議題，不是進行資料轉換的主要原因。","concept":"資料轉換原因","aiExplained":true},{"id":"web-b1-56","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c2","stem":"相對於非結構性資料，以下何者不是結構性資料的優點？","options":{"A":"資料類型一致性","B":"可節省儲存空間","C":"儲存資料具備彈性","D":"資料易於整併"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"結構性資料有固定欄位與型態，因此具備類型一致、節省儲存空間、易於整併等優點；但也因欄位結構固定，儲存內容缺乏彈性。儲存彈性反而是非結構性資料的特點，故 C 不是結構性資料的優點。","concept":"結構化資料特性","aiExplained":true},{"id":"web-b1-57","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c2","stem":"在執行資料分析時通常希望資料來源皆為結構化資料，但其實非結構化資料也具備某種程度的優勢，下列何者為真？","options":{"A":"非結構化資料顯示較仔細的資訊","B":"非結構化資料比較容易做區分","C":"非結構化資料較容易辨識","D":"以上皆是"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"非結構化資料（如文字、影音）保留完整的原始脈絡，能呈現比固定欄位更仔細、豐富的資訊，此為其優勢。但非結構化資料不易區分也不易辨識，處理成本高，故 B、C 皆錯，答案為 A。","concept":"非結構化資料特性","aiExplained":true},{"id":"web-b1-58","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c2","stem":"網頁爬蟲程式所擷取的資料形式為何？","options":{"A":"非結構性","B":"半結構性","C":"結構性","D":"以上皆非"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"網頁爬蟲擷取的是網頁上的文字、圖片等內容，這些內容沒有固定欄位與一致格式，屬於非結構性資料，通常需再經解析與整理轉成結構化形式後才能進行分析。","concept":"資料結構型態","aiExplained":true},{"id":"web-b1-59","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c2","stem":"現今透過網路或社群平台可蒐集到各式各樣的資訊，例如新商品的上架可以透過社群平台蒐集到客戶對此商品的文字評論，請問這些資料屬於何種性質？","options":{"A":"結構性","B":"半結構性","C":"非結構性","D":"以上皆非"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"社群平台上的文字評論是自由書寫的內容，沒有固定欄位、長度與格式，屬於非結構性資料；需經文字探勘等技術處理後，才能轉成可分析的結構化資訊。","concept":"資料結構型態","aiExplained":true},{"id":"web-b1-60","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c2","stem":"下列何者屬於機器學習（Machine learning）的分支，且是一種試圖使用複雜結構或多重非線性變換構成的多個處理層，並對資料進行高層抽象的演算法？","options":{"A":"人因工程（Human Factors）","B":"深度學習（Deep learning）","C":"最佳化理論（Optimization theory）","D":"作業研究（Operation research）"},"answer":"B","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"深度學習是機器學習的分支，利用多層非線性變換組成的處理層（深層神經網路）對資料進行高層次抽象與特徵學習，完全符合題述。人因工程、最佳化理論與作業研究皆非機器學習的分支。","concept":"深度學習","aiExplained":true},{"id":"web-b1-61","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c2","stem":"將非結構性資料轉化成易於分析的結構性資料時，往往需面臨什麼問題？","options":{"A":"資料不易取得","B":"過程容易發生錯誤","C":"重要訊息有可能流失","D":"資料一致性"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"把文字、影音等非結構性資料轉成固定欄位的結構化資料時，必須經過簡化與擷取，原始內容中的脈絡與細節無法完整保留，因此面臨的主要問題是重要訊息可能流失。","concept":"資料轉換風險","aiExplained":true},{"id":"web-b1-62","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c2","stem":"不符合原制定規則的資料須調查其原因，並研擬改善計劃，此動作為維護資料品質的哪一步驟？","options":{"A":"資料概述","B":"資料清理","C":"資料監控","D":"資料稽核"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"資料稽核是對不符合原制定規則的資料進行深入調查、追查其發生原因並研擬改善計畫的步驟。資料監控只是持續檢查資料是否符合規則，資料清理則是直接修正錯誤資料，兩者都不涉及原因調查與改善規劃。","concept":"資料品質維護-資料稽核","aiExplained":true},{"id":"web-b1-63","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c2","stem":"確定所分析的資料與原訂的商業目標是否相關，此動作為維護資料品質的哪一步驟？","options":{"A":"資料概述","B":"資料清理","C":"資料監控","D":"資料稽核"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"資料概述（data profiling）是在分析前先檢視資料的內容、結構與特性，確認資料是否與原訂的商業目標相關、是否適合後續分析，屬於維護資料品質的第一步。清理、監控與稽核則是後續處理與管控的步驟。","concept":"資料品質維護-資料概述","aiExplained":true},{"id":"web-b1-64","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c2","stem":"在資料生成、處理和管理的階段，可能會影響資料的品質，如重量資料合併時， 有些資料使用「公斤」為單位，有些使用「公克」為單位，請問此屬於哪一類的錯誤問題？","options":{"A":"資料精準度問題","B":"命名衝突問題","C":"度量衡問題","D":"以上皆非"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"同一種資料在不同來源以不同單位（公斤與公克）記錄，合併時產生的單位不一致屬於度量衡問題。命名衝突指的是欄位同名異義或異名同義，資料精準度則與量測誤差有關，皆非本題情境。","concept":"資料品質問題類型","aiExplained":true},{"id":"web-b1-65","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c2","stem":"資料品質的好壞會影響分析的結果，請問下列何者非資料品質的涵義？","options":{"A":"資料的正確性","B":"資料的可靠性","C":"資料的差異性","D":"資料的一致性"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"資料品質的涵義包括正確性、可靠性、一致性（以及完整性、時效性等）；「差異性」並非資料品質的衡量面向，故選 C。","concept":"資料品質涵義","aiExplained":true},{"id":"web-b1-66","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c2","stem":"為了提升資料品質，資料通常得經過整理並轉換作為分析前的準備，請問下列資料處理的方式何者有誤？","options":{"A":"填補正確的缺失數值","B":"控制極端值","C":"量化連續變數","D":"刪除定義不一致的資料"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"填補缺失值、控制極端值與變數量化轉換都是分析前常見且正確的資料前處理方式。定義不一致的資料應先統一定義、修正整併後再使用，若直接刪除會造成大量資訊損失並可能產生偏誤，故 D 的做法有誤。","concept":"資料前處理","aiExplained":true},{"id":"web-b1-67","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c2","stem":"某公司蒐集生產線一段期間的資料後發現，平均每生產1,000 件成品中，有850 件是良品，有100 件有瑕疵但堪用，其餘則完全無法使用。若已知一件成品不是良品，完全不能用的機率為何？","options":{"A":"0.05","B":"0.15","C":"0.25","D":"0.33"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"每1,000件中非良品共150件（100件瑕疵堪用＋50件完全不能用）。在已知成品不是良品的條件下，完全不能用的條件機率為50/150≈0.33，故選D。其他選項是誤用1,000件為分母或算錯不良品數所致。","concept":"條件機率","aiExplained":true},{"id":"web-b1-68","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c2","stem":"某一組資料其集中趨勢測量的平均數和中位數為10 和7，離散趨勢測量的標準差為2，此資料屬於何種分佈？","options":{"A":"正偏態分佈","B":"負偏態分佈","C":"無偏態分佈","D":"高狹峰分佈"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"平均數（10）大於中位數（7），表示分佈右側有較長的尾巴，屬於正偏態（右偏）分佈。若平均數小於中位數則為負偏態，兩者相等才接近對稱；峰態高低無法僅由平均數與中位數判斷。","concept":"偏態判斷（平均數與中位數）","aiExplained":true},{"id":"web-b1-69","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c2","stem":"若要用統計圖形來描述兩變數間的關係通常會使用何種圖形？","options":{"A":"直方圖","B":"散佈圖","C":"箱型圖","D":"以上皆可"},"answer":"B","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"散佈圖以兩軸分別代表兩個變數，每個點呈現一筆觀察值，可直接看出兩變數間關聯的方向與型態，是描述雙變數關係的標準圖形。直方圖與箱型圖都是描述單一變數分佈的工具，故不能選。","concept":"散佈圖與雙變數關係","aiExplained":true},{"id":"web-b1-70","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c2","stem":"依據柴比雪夫定理（Chebyshev's theorem），某公司員工紅利計畫，發放的平均金額為$50，標準差為$5。請問至少有多少員工比例的數值其紅利會落在平均加減2 個標準差範圍內？","options":{"A":"95%","B":"85%","C":"75%","D":"65%"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"柴比雪夫定理指出，不論資料分佈形狀為何，至少有1−1/k²的資料會落在平均數加減k個標準差內。k=2時，1−1/4=75%，故選C。95%是常態（鐘形）分配下經驗法則的結果，不適用於此定理。","concept":"柴比雪夫定理","aiExplained":true},{"id":"web-b1-71","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c2","stem":"長條圖（bar chart）與直方圖（histogram）為常見的資料圖示法，請問下列兩者之間的差異何者為真？","options":{"A":"兩者皆用於屬質資料","B":"兩者皆用於屬量資料","C":"長條圖用於屬質資料，直方圖用於屬量資料","D":"直方圖用於屬質資料，長條圖用於屬量資料"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"長條圖用於呈現類別（屬質）資料各類別的次數，長條之間通常分開；直方圖則用於連續（屬量）資料分組後的次數分配，長條彼此相連以表示數值的連續性。兩者適用的資料型態不同，故選C。","concept":"長條圖與直方圖的差異","aiExplained":true},{"id":"web-b1-72","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c2","stem":"利用箱形圖（box plot）可以很快看出資料統計的特性，請問在繪製時下列哪項資訊不須引入？","options":{"A":"Q1 第一個四分位數","B":"Q3 第三個四分位數","C":"標準差","D":"中位數"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"箱形圖是由最小值、第一四分位數Q1、中位數、第三四分位數Q3與最大值等五數綜合繪製而成，用以呈現資料的位置、離散與偏態。標準差並非繪製箱形圖所需的資訊，故選C。","concept":"箱形圖（五數綜合）","aiExplained":true},{"id":"web-b1-73","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c2","stem":"關於監督式學習（Supervised Learning）的敘述，下列哪一項正確？","options":{"A":"訓練資料沒有標準答案，不需要事先以人力給予標籤（Label）","B":"機器在學習時，並不知道其分類是否正確","C":"集群演算法（Clustering）為監督式學習方法之一","D":"監督式學習是在訓練的過程中告訴機器答案，資料事先給標籤"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"監督式學習的訓練資料須事先標註答案（標籤），機器在訓練過程中依標籤比對預測結果並修正模型，故D正確。A與B描述的是非監督式學習的特性，而集群演算法屬於非監督式學習，故C錯誤。","concept":"監督式與非監督式學習","aiExplained":true},{"id":"web-b1-74","subject":"B1","subjectName":"營運智慧概論","topic":"b1-c2","stem":"在監督式學習中，下列哪一項是迴歸模型與分類模型的主要區別方式？","options":{"A":"迴歸模型用於預測數值型目標變數，而分類模型用於預測類別型目標變數","B":"分類模型無法處理數據中的缺失值，迴歸模型可以","C":"迴歸模型只能用於時間序列數據，分類模型則不受限制","D":"分類模型的計算速度通常比迴歸模型快"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%911_%E7%87%9F%E9%81%8B%E6%99%BA%E6%85%A7%E6%A6%82%E8%AB%96_20251212112207.pdf","explanation":"迴歸與分類的根本差異在於目標變數的型態：迴歸模型預測連續數值（如營業額、溫度），分類模型預測離散類別（如良品/不良品），故A正確。缺失值處理、時間序列限制與計算速度都不是兩者的定義性區別。","concept":"迴歸與分類模型的區別","aiExplained":true},{"id":"web-b2-75","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"影響企業內部環境的組成因子。下列的因子何者為非？","options":{"A":"股東、董事會","B":"組織文化、組織結構","C":"管理程序及方法等","D":"政府、壓力團體"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"企業內部環境包含股東與董事會、組織文化與組織結構、管理程序及方法等存在於組織內部的因素。政府與壓力團體是來自組織外部的力量，屬於外部環境因子，故為非。","concept":"企業內部與外部環境","aiExplained":true},{"id":"web-b2-76","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"管理者運用組織資源達成目標的過程，為以下何者名詞的解釋？","options":{"A":"管理","B":"管理者","C":"組織","D":"目標"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"「管理」的定義就是管理者運用組織的人力、財務、物料與資訊等資源，透過規劃、組織、領導、控制等程序達成組織目標的過程。管理者是執行管理活動的人，組織與目標則分別是管理的場域與方向，皆非此定義本身。","concept":"管理的定義","aiExplained":true},{"id":"web-b2-77","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"管理中負責直接指揮，管理基層作業人員的日常工作，像是服務業及工廠中的領班，組長，金融業的襄理，科長，副理都屬之，通常稱為？","options":{"A":"第一線管理者","B":"中階管理者","C":"高階管理者","D":"作業管理者"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"第一線管理者（基層管理者）位於管理階層最底層，直接指揮與監督非管理職的基層作業人員之日常工作，如領班、組長等。中階管理者負責管理第一線管理者，高階管理者則負責全組織的決策與方向。","concept":"管理者層級","aiExplained":true},{"id":"web-b2-78","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"企業營運時常遇到需要做決策的情形，而決策的第一步即是確認問題所在。因此，要確認問題是什麼，身為一名經理要如何做？","options":{"A":"將一組標準或目標與另一組標準或目標進行比較","B":"尋找不滿意的顧客","C":"用直覺來找事情哪裡不對勁","D":"將當前情況與某些標準或目標進行比較"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"管理學上「問題」的定義是現況與期望狀態（標準或目標）之間的落差，因此確認問題的方法是將當前情況與標準或目標進行比較，故D正確。A比較的是兩組標準而非現況，B與C都不是系統性的問題確認方式。","concept":"決策程序－確認問題","aiExplained":true},{"id":"web-b2-79","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"決策過程包含八個步驟，起始自確認問題，結束於下列哪一個步驟？","options":{"A":"解決問題","B":"制定計劃來解決問題","C":"將問題分解成一系列步驟","D":"消除錯誤的替代方案"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"決策八步驟從確認問題開始，經過確立決策準則、分配權重、發展方案、分析方案、選擇方案、執行方案，最後以評估決策效能、確認問題是否獲得解決作結，因此整個過程結束於「解決問題」。其餘選項皆非決策程序的最後一個步驟。","concept":"決策八步驟","aiExplained":true},{"id":"web-b2-80","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"在非正式計畫中，目標通常是以何種方式與組織中的其他人共享？","options":{"A":"書面形式，但很少分享","B":"非書面形式，但很多分享","C":"書面形式，很多分享","D":"非書面形式，而且很少分享"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"非正式規劃的特徵是目標沒有書面化，多存在管理者腦中，且很少與組織其他成員分享。相對地，正式規劃會將具體目標寫成書面並廣泛地與組織成員溝通，故選D。","concept":"正式與非正式規劃","aiExplained":true},{"id":"web-b2-81","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"在管理四大功能中，規劃可分為正式規劃與非正式規劃。而正式規劃通常可獲得下列何種結果？","options":{"A":"較高的利潤","B":"生產力降低","C":"較高的銷售額，但利潤較低","D":"不同管理階層之間的緊張關係"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"研究顯示正式規劃通常與較佳的財務績效相關，例如較高的利潤與較高的資產報酬率，故選A。生產力降低、利潤較低或管理階層間的緊張關係都不是正式規劃的一般結果。","concept":"正式規劃的效益","aiExplained":true},{"id":"web-b2-82","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"組織設計要求經理必須做什麼事？","options":{"A":"決定誰領導組織內的團隊","B":"改變組織的文化","C":"改變或發展組織的結構","D":"改變組織的願景"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"組織設計是管理者建立、改變或發展組織結構的過程，涉及工作專業化、部門化、指揮鏈、控制幅度、集權與分權等決策，故選C。決定團隊領導人、改變文化或願景都不是組織設計的定義。","concept":"組織設計","aiExplained":true},{"id":"web-b2-83","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"何種部門化方式是基於領土或員工或客戶的實際位置？","options":{"A":"功能性","B":"產品","C":"地理區域","D":"矩陣"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"地理區域部門化是依營運地區或員工、客戶所在的實際位置來劃分部門，例如分為北區、中區、南區。功能性部門化依工作職能劃分，產品部門化依產品線劃分，矩陣式則是功能與專案雙重結構的組合。","concept":"部門化方式","aiExplained":true},{"id":"web-b2-84","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"指揮鏈（The chain of command）此概念可回答什麼問題？","options":{"A":"我可以在哪裡尋求幫助？","B":"我如何知道任務何時完成？","C":"規則是什麼？","D":"誰向誰報告？"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"指揮鏈是從組織最高層延伸至基層的職權連續線，明確界定上下從屬與報告關係，回答「誰向誰報告」的問題，故選D。它處理的是職權與報告路線，而非求助管道、任務完成判準或規則內容。","concept":"指揮鏈","aiExplained":true},{"id":"web-b2-85","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"下列關於動機的敘述，何者為非？","options":{"A":"永久的個人特質","B":"導致目標的過程","C":"因情況而異的事情","D":"需要指導的東西"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"動機是個人為達成目標而付出努力的過程，會隨情境不同而變動，並且可以被引導與激發，因此B、C、D都是動機的正確描述。動機並非固定不變的永久個人特質，故A的敘述為非。","concept":"動機的本質","aiExplained":true},{"id":"web-b2-86","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"馬斯洛需求層級理論（Maslow's Hierarchy of Needs Theory）為層級式結構是基於下列何種考量？","options":{"A":"所有需求都是平等的","B":"所有需求都很重要","C":"需求需要依順序來滿足","D":"需求永遠不會真正滿足"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"馬斯洛主張需求由低到高分為生理、安全、社會、尊重與自我實現五個層級，低層需求獲得相當程度的滿足後，較高層的需求才會成為主要的激勵力量，因此層級式結構正是基於需求須依順序滿足的考量，故選C。","concept":"馬斯洛需求層級理論","aiExplained":true},{"id":"web-b2-87","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"日本品管大師狩野紀昭（Noriaki Kano）提出「二維品質模式」，也稱為「狩野模型」（Kano model），以滿意度（顧客的主觀感受）和功能（產品的客觀機能） 為兩條軸線，畫出了二維平面，列舉出四種品質要素。當品質愈好，顧客滿意度愈高。與顧客滿意度呈現線性關係的品質要素是屬於哪一種品質？","options":{"A":"無差異品質（indifference）","B":"一維品質（one-dimensional）","C":"魅力品質（attractive）","D":"必要條件品質（must-be）"},"answer":"B","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"一維品質是指品質做得愈好顧客愈滿意、做得愈差愈不滿意，功能與滿意度呈線性關係，故選B。魅力品質是有則驚喜、無亦不會不滿；必要條件品質是有了視為理所當然、缺少則強烈不滿；無差異品質則與滿意度無明顯關聯。","concept":"Kano二維品質模式","aiExplained":true},{"id":"web-b2-88","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"下列哪一項不是魅力型領導者的典型特徵？","options":{"A":"直接的目光接觸","B":"放鬆的身體姿勢","C":"熱烈的臉部表情","D":"僵硬的身體姿勢"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"魅力型領導者通常展現自信與感染力，典型特徵包括直接的目光接觸、放鬆自然的身體姿勢與生動熱烈的臉部表情。僵硬的身體姿勢與這種自信開放的形象相反，並非魅力型領導者的典型特徵，故選D。","concept":"魅力型領導","aiExplained":true},{"id":"web-b2-89","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"管理具備四大功能，各功能各司其職並前後相關。請從下列敘述選擇正確的功能與依序步驟？","options":{"A":"控制—規劃—領導—組織","B":"規劃—組織—領導—控制","C":"組織—控制—領導—規劃","D":"領導—控制—規劃—組織"},"answer":"B","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"管理四大功能的順序為：先「規劃」設定目標與策略，再「組織」安排資源與工作結構，接著「領導」激勵並指揮成員執行，最後「控制」監控績效並修正偏差，故選B。","concept":"管理四大功能","aiExplained":true},{"id":"web-b2-90","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"有效的控制可以幫助管理者達成何種任務？","options":{"A":"賦予員工權力","B":"延遲目標","C":"風險最大化","D":"盡量減少員工的權力"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"有效的控制系統能提供員工績效的資訊與回饋，降低授權後可能發生問題的風險，讓管理者能放心地賦予員工權力（授權），故選A。延遲目標、風險最大化與削減員工權力都與控制的目的相違背。","concept":"控制與授權","aiExplained":true},{"id":"web-b2-91","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"控制過程的第一步為？","options":{"A":"採取行動","B":"衡量實際表現","C":"將實際性能與標準進行比較","D":"將標準與理想進行比較"},"answer":"B","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"控制過程包含三個步驟：衡量實際表現、將實際表現與標準比較、採取管理行動修正偏差，因此第一步是衡量實際表現，故選B。作為比較基準的標準本身是在規劃功能中設定的，不屬於控制過程的步驟。","concept":"控制過程三步驟","aiExplained":true},{"id":"web-b2-92","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"控制功能可確保下列何者在組織中完成？","options":{"A":"設定目標","B":"達成目標","C":"制定計劃","D":"制定策略"},"answer":"B","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"控制功能透過監控實際績效、與目標比較並修正偏差，確保組織的目標能夠被達成，故選B。設定目標、制定計畫與制定策略都屬於規劃功能的範疇，而非控制功能。","concept":"控制功能的目的","aiExplained":true},{"id":"web-b2-93","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"下列敘述何者最能說明基礎研究與應用研究的差異？","options":{"A":"基礎研究的目標是要了解原因，應用研究的目標是要預測問題","B":"基礎研究的目的在於增加人類的知識，應用研究的目的是要改善人類狀況","C":"基礎研究的方法是採用科學性的研究，應用研究的方法是採用描述性的研究","D":"基礎研究的研究哲學是現實的，應用研究的研究哲學是抽象的"},"answer":"B","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"基礎研究以增進人類知識、建立與發展理論為目的；應用研究則以解決實際問題、改善人類生活狀況為目的，故B最能說明兩者差異。A、C、D對兩種研究的目標、方法與哲學之描述均不正確。","concept":"基礎研究與應用研究","aiExplained":true},{"id":"web-b2-94","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"那一種研究是基於研究者的好奇心興趣，而所進行的研究，其研究目的在於求知以發現知識，與知識體系理論化發展有密切關聯？","options":{"A":"基礎研究","B":"應用研究","C":"評鑑研究","D":"行動研究"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"基礎研究源自研究者的好奇心與求知興趣，目的在發現新知識並促進知識體系的理論化發展，故選A。應用研究著重解決實務問題，評鑑研究針對方案成效進行評估，行動研究則是實務工作者為改善現場問題所做的研究。","concept":"研究類型","aiExplained":true},{"id":"web-b2-95","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"小明原本是某公司人力資源部門的員工，專責新進員工職前教育訓練的執行工作，工作半年後，部門主管將員工在職訓練的執行工作也交給小明負責。然後又經過半年，除了原先員工教育訓練的執行工作之外，部門主管開始讓小明負責員工教育訓練的規劃工作與執行後的考評工作。工作2 年後，部門主管將小明調離員工教育訓練的職位，請小明負責擬定員工招募計畫與執行招募活動等工作。請問部門主管對小明工作的調整，依事件發生的順序分別屬於哪一類型的工作擴張？（1）工作擴大化；（2）工作輪調；（3）工作豐富化","options":{"A":"123","B":"132","C":"321","D":"312"},"answer":"B","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"第一次調整是增加同層次的在職訓練「執行」工作，屬水平擴充的工作擴大化(1)；第二次加入規劃與考評工作，提升工作的自主性與責任深度，屬垂直擴充的工作豐富化(3)；第三次調離原職改負責招募，是轉換至不同職務的工作輪調(2)。依序為1→3→2，故選B。","concept":"工作設計（擴大化、豐富化、輪調）","aiExplained":true},{"id":"web-b2-96","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"下列何者是持續製程改善計畫所強調的？","options":{"A":"採取預防行動，避免錯誤發生","B":"錯誤發生時如何找出錯誤","C":"錯誤發生後如何改善","D":"試圖掩飾錯誤避免被發現"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"持續製程改善（如TQM、PDCA循環）強調事前預防重於事後補救，透過不斷改善流程來避免錯誤與不良品的發生，故選A。B與C都是事後偵錯與補救的思維，D更是違反品質管理的原則。","concept":"持續製程改善","aiExplained":true},{"id":"web-b2-97","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"要獲得即時化生產（Just in time）的效益，其中關鍵在於製造廠商與供應廠商必須培養何種關係？","options":{"A":"合夥關係","B":"競爭關係","C":"對立關係","D":"無關係"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"JIT 及時生產要求供應商在正確時間、以正確數量交付正確品質的物料，幾乎沒有庫存緩衝，因此製造商與供應商必須建立長期互信的合夥關係，共享生產排程與需求資訊。競爭或對立關係會使資訊不透明、交期不可靠，JIT 便無法運作。","concept":"及時化生產（JIT）與供應商關係","aiExplained":true},{"id":"web-b2-98","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"性別、年齡、職業等為市場區隔變數中的哪種變數？","options":{"A":"人口統計變數","B":"行為變數","C":"地理變數","D":"策略變數"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"性別、年齡、職業、所得、教育程度等描述人口組成特徵的變數，屬於人口統計變數。行為變數指購買頻率、使用時機、品牌忠誠度等；地理變數指國家、城市、氣候等；市場區隔中並沒有「策略變數」這一類。","concept":"市場區隔變數","aiExplained":true},{"id":"web-b2-99","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"行銷觀念中只重視企業利潤是指何種概念？","options":{"A":"銷售觀念","B":"利害關係人觀念","C":"社會行銷觀念","D":"創新觀念"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"銷售觀念強調靠大量推銷與促銷把產品賣出去以創造企業利潤，出發點是企業自身，較不考慮顧客真正需求或社會福祉。社會行銷觀念則要求兼顧企業利潤、顧客需求與社會整體利益，利害關係人觀念也強調多方權益，皆非「只重視企業利潤」。","concept":"行銷觀念演進（銷售觀念）","aiExplained":true},{"id":"web-b2-100","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"成熟產業的產品訂價方法比較適合何種訂價方法？","options":{"A":"成本導向","B":"競爭導向","C":"顧客導向","D":"道德導向"},"answer":"B","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"成熟產業中產品同質性高、競爭者眾多，消費者容易比價，價格主要受市場競爭牽制，因此適合以競爭者價格為基準的競爭導向訂價。成本導向適用於缺乏市場參考時，顧客導向較適合差異化或新價值產品，成熟市場中單靠這兩者容易偏離市場行情。","concept":"訂價方法（競爭導向訂價）","aiExplained":true},{"id":"web-b2-101","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"下列何者敘述較符合產品生命週期中成長期的特性？","options":{"A":"銷售量急遽攀升","B":"利潤為負","C":"推銷費用高","D":"銷售量難以起色"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"成長期的特徵是產品已被市場接受，銷售量急遽攀升、利潤快速成長。利潤為負、推銷費用高、銷售量難以起色都是導入期的典型特性，此時產品知名度低、需大量促銷且尚未達到經濟規模。","concept":"產品生命週期（成長期特性）","aiExplained":true},{"id":"web-b2-102","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"說明一個員工若要順利執行某一特定工作必備的基本資格，有效執行該工作所要具備的知識、技術與能力的書面說明，稱為？","options":{"A":"工作說明書","B":"策略規範書","C":"作業計畫書","D":"行銷企劃書"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"描述執行某項工作所需資格、知識、技術與能力（KSA）的書面文件，是工作分析的產出文件，在選項中對應「工作說明書」。策略規範書、作業計畫書、行銷企劃書都不是人力資源管理中定義工作資格條件的文件。","concept":"工作分析與工作說明書","aiExplained":true},{"id":"web-b2-103","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"A 公司販賣無痛皮下注射器給醫院，年度需求量20,000 單位，每筆訂單的訂購成本25 元，每單位商品持有成本4 元，試問下列何者正確？","options":{"A":"經濟訂購量500 單位","B":"年度訂購成本1,000 元","C":"年度存貨持有成本1,000 元","D":"以上皆是"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"EOQ＝√(2×20,000×25÷4)＝√250,000＝500 單位。年訂購次數＝20,000÷500＝40 次，年度訂購成本＝40×25＝1,000 元；平均存貨＝500÷2＝250 單位，年度持有成本＝250×4＝1,000 元。A、B、C 皆正確，故選「以上皆是」。","concept":"經濟訂購量（EOQ）計算","aiExplained":true},{"id":"web-b2-104","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"製作產品所需組件、成分以及原料的數量清單，一般簡稱BOM，係指下列何者？","options":{"A":"物料清單","B":"採購單","C":"驗收單","D":"加工單"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"BOM 是 Bill of Materials 的縮寫，即物料清單，列出製造一項產品所需的所有組件、成分、原料及其數量與層次結構，是 MRP 與 ERP 系統的核心基礎資料。採購單、驗收單、加工單都是作業單據，與 BOM 的定義不符。","concept":"物料清單（BOM）","aiExplained":true},{"id":"web-b2-105","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"為了讓企業外部者能了解企業的財務資訊，此為","options":{"A":"財務會計","B":"成本會計","C":"管理會計","D":"稅務會計"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"財務會計的目的是依一般公認會計原則編製財務報表，提供股東、債權人、投資人等企業外部使用者了解企業財務狀況。成本會計與管理會計服務對象是企業內部管理者，稅務會計則是為了申報納稅，皆非以外部使用者為主要對象。","concept":"財務會計與管理會計的區別","aiExplained":true},{"id":"web-b2-106","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"以下哪個職務的工作職責是執行企業內部控制，並應獨立向董事會報告？","options":{"A":"會計主管","B":"財務主管","C":"稽核人員","D":"總經理"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"內部稽核人員負責查核與評估企業內部控制制度的有效性，且組織上須獨立於各營運部門，直接向董事會（或審計委員會）報告，以確保稽核的客觀與獨立性。會計主管、財務主管與總經理本身是被稽核的執行單位，不具此獨立報告職責。","concept":"內部控制與內部稽核","aiExplained":true},{"id":"web-b2-107","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"負責計算企業生產與配銷過程中相關的各項成本是指何種人員？","options":{"A":"管理會計人員","B":"成本會計人員","C":"財務人員","D":"行銷專案人員"},"answer":"B","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"成本會計人員專門負責蒐集、記錄與計算產品在生產與配銷過程中發生的材料、人工與製造費用等各項成本，作為存貨評價與定價決策的依據。管理會計人員偏重提供內部決策分析資訊，財務人員負責資金調度，範圍與此職責不同。","concept":"成本會計職能","aiExplained":true},{"id":"web-b2-108","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"下列何者為非常用的獲利率指標？","options":{"A":"邊際利潤率","B":"投資報酬率","C":"每股盈餘","D":"流動比率"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"流動比率（流動資產÷流動負債）衡量的是企業短期償債能力，屬於流動性指標而非獲利性指標。邊際利潤率、投資報酬率、每股盈餘都是衡量企業賺錢能力的常用獲利指標。","concept":"財務比率分類（獲利性 vs 流動性）","aiExplained":true},{"id":"web-b2-109","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"說明企業在某一特定日期的財務狀況的報表是指？","options":{"A":"損益表","B":"現金流量表","C":"資產負債表","D":"甘特圖"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"資產負債表表達企業在「某一特定日期」（時點）的資產、負債與股東權益狀況，故又稱財務狀況表。損益表與現金流量表表達的是「某一期間」的經營成果與現金流量，甘特圖則是專案排程工具，不是財務報表。","concept":"資產負債表（時點報表）","aiExplained":true},{"id":"web-b2-110","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"假設有一家買賣業公司的營業循環日數為73 日，已知其存貨週轉率為10 次， 請問下列敘述何者正確？","options":{"A":"該公司應收款項週轉率為10 次","B":"該公司平均銷貨日數為10 日","C":"該公司平均收現日數為63 日","D":"該公司應付款項週轉率為10 次"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"存貨週轉率 10 次表示平均銷貨日數＝365÷10＝36.5 日；營業循環＝平均銷貨日數＋平均收現日數，故平均收現日數＝73－36.5＝36.5 日，應收款項週轉率＝365÷36.5＝10 次，A 正確。B 應為 36.5 日、C 應為 36.5 日皆錯，D 的應付款項週轉率無法由題目資訊推得。","concept":"營業循環與週轉率計算","aiExplained":true},{"id":"web-b2-111","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"現金流量表是指企業三項主要活動的現金流入與流出狀況，不包括下列哪一項？","options":{"A":"資產總額","B":"營業","C":"投資","D":"融資"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"現金流量表的三大活動分類為營業活動、投資活動與融資活動的現金流入與流出。資產總額是資產負債表上的存量金額，不是現金流量表的活動分類。","concept":"現金流量表三大活動","aiExplained":true},{"id":"web-b2-112","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"下列何者能衡量企業的清償能力？","options":{"A":"流動比率","B":"存貨週轉率","C":"獲利率","D":"股價變動率"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"流動比率＝流動資產÷流動負債，衡量企業以流動資產償還短期債務的能力，是典型的清償能力（流動性）指標。存貨週轉率屬經營效率指標，獲利率屬獲利能力指標，股價變動率則反映市場評價，皆非清償能力指標。","concept":"流動比率與清償能力","aiExplained":true},{"id":"web-b2-113","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"為了達成規劃的目的包含下列的步驟：（1）由基層督導者帶領員工執行 （2）由高階層經營者設定組織使命、總體預定目標和策略（3）中階層管理者在各部門設立部門目標。請問正確的順序為何？","options":{"A":"312","B":"123","C":"132","D":"231"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"規劃是由上而下展開：先由高階經營者設定組織使命、總體目標與策略（2），再由中階管理者依此設立各部門目標（3），最後由基層督導者帶領員工實際執行（1），故正確順序為 231。","concept":"規劃的層級展開（由上而下）","aiExplained":true},{"id":"web-b2-114","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"下列何者沒有被包含在企業流程再造中？","options":{"A":"道德文化","B":"顧客關係","C":"營運品質","D":"創新及作業績效"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"企業流程再造（BPR）是對企業流程進行根本性的重新思考與徹底重新設計，目標在改善顧客關係、營運品質、成本、速度與創新及作業績效等關鍵績效面向。道德文化屬於企業倫理與組織文化範疇，不是 BPR 所涵蓋的流程改造目標。","concept":"企業流程再造（BPR）","aiExplained":true},{"id":"web-b2-115","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"組織的任何管理層級都有其關鍵績效指標，其設計基本原理應該是依循？","options":{"A":"由上而下","B":"由下而上","C":"目標管理","D":"部門自行訂定"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"KPI 的設計應由上而下展開：先從組織的願景、策略與總體目標出發，再逐層分解為部門與個人的關鍵績效指標，確保各層級指標與組織策略對齊。若由下而上或各部門自行訂定，容易造成指標與整體策略脫節。","concept":"關鍵績效指標（KPI）設計原則","aiExplained":true},{"id":"web-b2-116","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"SWOT 分析完成後，管理人員將依據分析過程中出現的問題以何種方式解決？","options":{"A":"消除策略","B":"實施策略","C":"評估策略","D":"制定策略"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"策略管理程序是先進行環境與 SWOT 分析，接著針對分析發現的優劣勢與機會威脅「制定策略」，之後才是實施策略與評估策略。SWOT 完成後的下一步是依據結果制定因應策略，故選 D。","concept":"策略管理程序（SWOT 之後制定策略）","aiExplained":true},{"id":"web-b2-117","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"國家或地區的居民文化水平、風俗習慣、宗教信仰可被歸類在PEST 分析中的何類環境之中？","options":{"A":"政治法律環境（Political）","B":"經濟環境（Economic）","C":"社會文化環境（Socio-cultural）","D":"技術環境（Technological）"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"PEST 分析中，社會文化環境（Socio-cultural）涵蓋人口結構、文化水平、風俗習慣、宗教信仰、價值觀與生活型態等因素，題目所列項目正屬此類。政治法律環境指政策法規，經濟環境指景氣與所得，技術環境指科技發展。","concept":"PEST 分析（社會文化環境）","aiExplained":true},{"id":"web-b2-118","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"「該事業單位處於成熟期，產品市場佔有率高，具有競爭優勢，為公司創造穩定的現金流。」請問以上所述較符合BCG 矩陣（Boston Consulting Group Matrix） 分析的何種事業？","options":{"A":"笨狗型事業（Dogs）","B":"金牛型事業（Cash Cows）","C":"問題型事業（Question Marks）","D":"明星型事業（Stars）"},"answer":"B","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"金牛型事業的特徵是市場成長率低（成熟期）但相對市場佔有率高，不需大量投資即可產生穩定豐沛的現金流，正符合題目描述。明星是高成長高佔有率、問題兒童是高成長低佔有率、笨狗則是低成長低佔有率。","concept":"BCG 矩陣（金牛型事業）","aiExplained":true},{"id":"web-b2-119","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"此工具是公司進行產品組合或事業組合分析與管理的重要工具，其可幫助公司找出最佳獲利的產品或事業單位，決定資源分配以達企業獲利極大化。請問以上所述之策略分析工具是指何者？","options":{"A":"安索夫策略分析","B":"SWOT 分析","C":"BCG 矩陣","D":"波特五力分析"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"BCG 矩陣以市場成長率與相對市場佔有率兩個維度，將事業單位分為明星、金牛、問題兒童與笨狗四類，正是用於產品組合／事業組合分析與資源分配決策的工具。安索夫矩陣分析成長方向，SWOT 分析內外部環境，五力分析評估產業競爭結構，皆非組合管理工具。","concept":"BCG 矩陣（事業組合分析）","aiExplained":true},{"id":"web-b2-120","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c1","stem":"以波特五力分析而言，當具拍照功能的智慧型手機在市場中出現，消費者不再使用相機而改用智慧手機時，相機廠商受到何種威脅？","options":{"A":"客戶的議價能力","B":"新進者的威脅","C":"供應商議價能力","D":"替代品的威脅"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"智慧型手機屬於不同產業的產品，卻能滿足消費者「拍照」的相同需求並取代相機，這是典型的替代品威脅。新進者威脅指同產業的新競爭者進入，智慧手機廠商並非進入相機產業，而是以替代品搶走需求。","concept":"波特五力分析（替代品威脅）","aiExplained":true},{"id":"web-b2-121","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"價值鏈是一種價值創造分析的工具，適合用於說明企業的價值創造邏輯及過程。價值鏈活動分為主要活動及支援活動，以下何種活動屬於支援活動？","options":{"A":"出貨後勤","B":"行銷與銷售","C":"技術研發","D":"製造營運"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"價值鏈的主要活動包括進貨後勤、製造營運、出貨後勤、行銷與銷售、售後服務；支援活動則包括企業基礎設施、人力資源管理、技術研發與採購。技術研發屬於支援活動，其餘三個選項皆為主要活動。","concept":"價值鏈（主要活動 vs 支援活動）","aiExplained":true},{"id":"web-b2-122","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"Al-Debei and Avison 針對過去許多學者對商業模式的描述，提出四個完整的構面來建構商業模式，包括價值主張、價值組態，價值結構與價值財務等構面。 企業以資訊系統協助辨識目標客群並提出能為其創造價值的商業營運邏輯，這是屬於哪一個構面的活動？","options":{"A":"價值主張","B":"價值組態","C":"價值結構","D":"價值財務"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"價值主張構面描述企業提供什麼產品或服務、鎖定哪些目標客群，以及能為顧客創造什麼價值，題目中「辨識目標客群並提出創造價值的營運邏輯」正是價值主張的核心內容。價值組態談資源與活動的配置，價值結構談組織與夥伴網絡，價值財務談成本與收益模式。","concept":"商業模式四構面（價值主張）","aiExplained":true},{"id":"web-b2-123","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"下列何者為一種新產品或服務，通常由於科技進步所帶來的，具有重新形塑整個產業的潛力。例：Kodak？","options":{"A":"破壞式創新","B":"維持性創新科技","C":"創造性破壞","D":"生態系統"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"破壞式創新指由科技進步帶來的新產品或服務，具有重新形塑整個產業的潛力，如數位攝影顛覆了 Kodak 主導的底片產業。維持性創新只是在既有產品上漸進改良，創造性破壞描述的是新舊更替的經濟過程而非產品本身。","concept":"破壞式創新","aiExplained":true},{"id":"web-b2-124","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"下列何者威脅到一個產業現有存在者的情況，新進者利用新科技找到獲利方法，而現存者拒絕改變且設法保護他們舊有的商業模式？","options":{"A":"維持性創新科技","B":"創造性破壞","C":"破壞式創新","D":"現有競爭者之間的競爭"},"answer":"B","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"創造性破壞（熊彼得提出）描述的是一種過程：新進者運用新科技找到新的獲利方式，逐步取代拒絕改變、固守舊商業模式的現存者，使產業舊秩序被摧毀、新秩序建立。破壞式創新指的是新產品或服務本身，維持性創新是漸進改良，皆與此過程性定義不同。","concept":"創造性破壞","aiExplained":true},{"id":"web-b2-125","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"下列何者為一種以矩陣式，利用點與空白依一定規則編排，能儲存3,000 多位元的一種二維條碼，可以對多種資料進行編碼？","options":{"A":"Barcode","B":"QR Code","C":"Encryption","D":"Encoder"},"answer":"B","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"QR Code 是以正方形矩陣排列黑點與空白的二維條碼，儲存容量遠大於傳統一維條碼，可對數字、文字、網址等多種資料編碼。Barcode 一般指一維條碼，Encryption 是加密、Encoder 是編碼器，皆非二維條碼。","concept":"QR Code（二維條碼）","aiExplained":true},{"id":"web-b2-126","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"下列何者為另一種軟體開發與散布的管道，其授權條款必須符合某些條件，其中一項就是免費散布？","options":{"A":"Open Data","B":"Open Source Software","C":"Software as a Service（SaaS）","D":"Commercial off-the-shelf（COTS）"},"answer":"B","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"開放原始碼軟體（Open Source Software）是一種軟體開發與散布模式，其授權條款須符合開放原始碼定義的條件，包括允許自由（免費）再散布、公開原始碼等。Open Data 指開放資料而非軟體，SaaS 是雲端訂閱服務，COTS 是商用現成套裝軟體。","concept":"開放原始碼軟體（OSS）","aiExplained":true},{"id":"web-b2-127","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"下列何者為對某個市場提供差異化產品或服務，找出一群有特殊偏好的消費者，為他們量身打造？","options":{"A":"低成本領導策略","B":"產品差異化策略","C":"聚焦利基策略","D":"競爭五力"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"聚焦利基策略的重點是鎖定「一群有特殊偏好的消費者」這個狹窄的目標區隔，為其量身打造產品或服務。產品差異化策略雖也強調差異化，但訴求對象是廣泛的整體市場而非特定利基客群；低成本領導以價格取勝，競爭五力則是產業分析工具而非競爭策略。","concept":"波特一般性競爭策略（聚焦利基）","aiExplained":true},{"id":"web-b2-128","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"下列何者為波特的提出用以描述企業為了創造價值而進行的活動，向供應商購入原料，再以某種方法製造出商品，然後將產品或服務賣給消費者？","options":{"A":"生態系統","B":"競爭力模式","C":"五力分析","D":"價值鏈模型"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"價值鏈模型是波特提出用來描述企業創造價值過程的工具，將「進料—製造—出貨—行銷銷售—服務」等一連串活動串成一條鏈，正對應題目所述從購入原料、製造到銷售給消費者的流程。五力分析同為波特提出，但用於分析產業競爭結構，而非企業內部價值創造活動。","concept":"價值鏈模型","aiExplained":true},{"id":"web-b2-129","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"價值鏈模型提供可用甚麼讓企業組織將其執行效率與該行業做比較，看他們排行如何，也可藉此看出哪些地方需要改進？","options":{"A":"檢驗基準","B":"主要活動","C":"支援活動","D":"競爭力"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"價值鏈分析可搭配檢驗基準（benchmark，標竿）使用：企業將自身各項活動的執行效率與同業最佳實務比較，了解自己的相對排名，並找出需要改進的環節。主要活動與支援活動是價值鏈的活動分類，並非用來做同業比較的工具。","concept":"價值鏈與標竿比較（benchmarking）","aiExplained":true},{"id":"web-b2-130","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"下列何者為軟體的所有權、執行環境、管理都由供應商從遠端提供的一種資訊系統，企業組織依照使用量給付租賃費用，並透過網路來存取該服務？","options":{"A":"Infrastructure as a Service, IaaS","B":"Data as a Service, DaaS","C":"Platform as a Service, PaaS","D":"Software as a Service, SaaS"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"SaaS（軟體即服務）是由供應商在遠端擁有並管理軟體與其執行環境，企業依使用量付費、透過網路直接使用軟體服務，正符合題幹描述。IaaS 提供的是運算、儲存等基礎設施，PaaS 提供開發與部署平台，兩者都不是直接提供「軟體」本身給使用者。","concept":"雲端服務模式（SaaS/PaaS/IaaS）","aiExplained":true},{"id":"web-b2-131","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"下列何者不屬於協同合作與社群企業的資訊工具及科技？","options":{"A":"自動倉儲系統","B":"維基（Wiki）平台","C":"電子郵件","D":"虛擬會議系統"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"維基平台、電子郵件與虛擬會議系統都是支援人與人之間溝通、分享與協同作業的社群協作工具。自動倉儲系統屬於物流與生產作業自動化設備，目的在提升倉儲作業效率，與協同合作或社群企業溝通無關，故為正確答案。","concept":"協同合作工具","aiExplained":true},{"id":"web-b2-132","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"企業在距離500 公尺的範圍內，將所擁有的電腦及伺服器以網路連接，彼此分享資料與數位裝置資源，這樣的網路類型通常稱為？","options":{"A":"校園網路","B":"廣域網路","C":"區域網路","D":"都會網路"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"區域網路（LAN）指在數百公尺至數公里內（如同一棟建築或園區）連接電腦與伺服器、共享資料與設備資源的網路，500 公尺範圍正屬於 LAN 的典型涵蓋範圍。廣域網路（WAN）跨越城市或國家，都會網路（MAN）涵蓋整個城市，範圍都遠大於題幹所述。","concept":"網路類型（LAN/MAN/WAN）","aiExplained":true},{"id":"web-b2-133","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"下列何者為政府機構提倡的政策，例如：休閒旅遊、交通運輸，這些資料公開有助於共享經濟的供需雙方更深入地瞭解市場？","options":{"A":"應用程式介面","B":"行動運算","C":"開放資料","D":"社群運算"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"開放資料（Open Data）是政府將旅遊、交通等公共資料以開放格式釋出供大眾自由取用的政策，能讓共享經濟的供需雙方更瞭解市場。API 只是程式介接的技術手段，行動運算與社群運算則是運算型態，皆非政府資料公開政策。","concept":"開放資料（Open Data）","aiExplained":true},{"id":"web-b2-134","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"下列何者為整合社群網站上朋友之間貢獻與分享的各種訊息與評論，並且利用行動商務無所不在的特性，結合雲端運算平台，提供資訊系統的硬體、軟體、 資料庫、APP 以及Server 的一種平台？","options":{"A":"M-Shopping","B":"Mobile Payment","C":"SoMoCLo（Social, Mobile, Cloud）","D":"Blockchain"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"題幹同時提到社群分享（Social）、行動商務無所不在（Mobile）與雲端運算平台（Cloud）三項元素，正是 SoMoClo 的整合概念。M-Shopping 與 Mobile Payment 只涵蓋行動購物或付款單一面向，Blockchain 則是分散式帳本技術，皆不符合三者整合的描述。","concept":"SoMoClo（社群、行動、雲端整合）","aiExplained":true},{"id":"web-b2-135","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"下列哪些因素無法解釋，為什麼今天的運算資源比以前幾十年更加可用？","options":{"A":"網路經濟","B":"大量數位儲存定律","C":"摩爾定律","D":"允許各種技術標準共存，並廣泛拒絕技術標準"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"運算資源愈來愈便宜可得，可由摩爾定律（晶片效能倍增、成本下降）、大量數位儲存定律（儲存成本快速下降）與網路經濟（Metcalfe 定律，網路價值隨使用者增加）解釋。真正促成的是業界「廣泛接受並遵循共同技術標準」，選項 D 說「廣泛拒絕技術標準」與事實相反，故無法解釋，為正確答案。","concept":"運算資源驅動因素（摩爾定律等）","aiExplained":true},{"id":"web-b2-136","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"下列何種平台對供需雙方做真正的身分認證，並瞭解雙方真正的生活背景。此外，平台上的評價、推薦、排名及評論系統，也都可以用來評估當事者的信用狀況，提升雙方交易的信任程度？","options":{"A":"行動運算","B":"社群運算","C":"行動付款","D":"開放資料"},"answer":"B","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"社群運算平台透過社群帳號的身分認證、生活背景資訊，以及評價、推薦、排名與評論等社群機制，建立供需雙方的信任，是共享經濟交易信任的基礎。行動運算與行動付款只解決存取與支付問題，開放資料是政府資料公開政策，均不具備社群信任評估機制。","concept":"社群運算與信任機制","aiExplained":true},{"id":"web-b2-137","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"利用感測器、語言、臉部辨識裝置，來偵測使用者的各種情緒狀態，並由AI 智慧系統判讀分析，並自動執行某些適當的反應行動系統，此稱為？","options":{"A":"擴增實境","B":"情境感知運算","C":"情緒運算","D":"物聯網"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"情緒運算（Affective Computing）專門透過感測器、語音與臉部辨識偵測使用者的「情緒狀態」，再由 AI 判讀並做出適當回應，與題幹完全吻合。情境感知運算偵測的是使用者所處的「環境資訊」而非情緒，擴增實境是虛實疊合的顯示技術，物聯網則是裝置連網的整體架構。","concept":"情緒運算（Affective Computing）","aiExplained":true},{"id":"web-b2-138","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"下列何者為一種感測器（Sensor）、行動運算與AI，並透過對使用者各種環境資訊的蒐集、傳遞、分析後，系統採取最適當的反應行為或傳遞最合適資訊的一種技術？","options":{"A":"適地性（Location-based Service, LBS）","B":"行動社群網路","C":"情緒運算","D":"Context Aware Computing, CAC"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"情境感知運算（Context Aware Computing）結合感測器、行動運算與 AI，蒐集並分析使用者所處的各種「環境資訊」（位置、時間、活動等），再主動提供最合適的回應或資訊，正是題幹描述。LBS 僅利用位置單一情境，情緒運算偵測的是情緒而非環境，行動社群網路則與環境感知無關。","concept":"情境感知運算（CAC）","aiExplained":true},{"id":"web-b2-139","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"AirBnb、Uber、P2P 借貸屬於哪種社群商務？","options":{"A":"社群網路行銷","B":"點對點P2P 的共享經濟","C":"社群團購","D":"線上口碑行銷"},"answer":"B","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"Airbnb（閒置房間出租）、Uber（私家車載客）與 P2P 借貸都是讓個人對個人直接媒合、共享閒置資源或資金的商業模式，屬於點對點（P2P）共享經濟。社群網路行銷、社群團購與線上口碑行銷都是行銷或購買手法，並非資源共享的交易模式。","concept":"共享經濟（P2P）","aiExplained":true},{"id":"web-b2-140","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"運用一些策略來增強搜尋引擎的流量，通常是透過改進網站在搜尋結果頁上的排名位置來達成目的，此稱為？","options":{"A":"Tag cloud","B":"Search engine optimization（SEO）","C":"Click-through rate（CTR）","D":"third-party cookie"},"answer":"B","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"搜尋引擎最佳化（SEO）就是透過調整網站內容與結構，提升網站在搜尋結果頁的自然排名，進而增加流量。Tag cloud 是標籤視覺化呈現，CTR 是衡量點擊成效的指標，第三方 cookie 是跨站追蹤技術，都不是提升搜尋排名的策略。","concept":"搜尋引擎最佳化（SEO）","aiExplained":true},{"id":"web-b2-141","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"用來支援企業內部重要營運流程，包括財務與會計流程、人力資源流程、製造與生產流程及業務行銷流程的整合企業系統通稱為：","options":{"A":"企業資源規劃ERP 系統","B":"決策支援系統","C":"高階主管系統","D":"專家系統"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"ERP（企業資源規劃）系統以單一整合平台串接財會、人資、製造生產與業務行銷等企業核心營運流程，讓資料在各部門間即時共享，正符合題幹「整合企業系統」的描述。決策支援系統與高階主管系統偏重輔助決策，專家系統則模擬專家推理，都不是整合日常營運流程的系統。","concept":"企業資源規劃（ERP）","aiExplained":true},{"id":"web-b2-142","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"先進規劃與排程系統（Advanced Planning and Scheduling, APS）通常不包含下列哪項功能？","options":{"A":"需求規劃","B":"行銷資源規劃","C":"產能規劃","D":"物料規劃"},"answer":"B","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"APS 是針對生產與供應鏈的最佳化規劃工具，核心功能包括需求規劃、產能規劃、物料規劃與生產排程等。行銷資源規劃屬於行銷管理範疇，不在 APS 的生產規劃功能之列，故為正確答案。","concept":"先進規劃與排程系統（APS）","aiExplained":true},{"id":"web-b2-143","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"下列何種資料分析技術不屬於資料探勘系統中的常用技術？","options":{"A":"集群分析","B":"關聯分析","C":"樞紐分析","D":"時間序列分析"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"集群分析、關聯分析與時間序列分析都是資料探勘的經典技術，分別用於分群、找出項目間關聯規則與預測趨勢。樞紐分析（Pivot Analysis）是試算表或 OLAP 中對資料做多維度彙總的工具，屬於描述性報表分析而非資料探勘技術。","concept":"資料探勘技術","aiExplained":true},{"id":"web-b2-144","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"下列何者為一種企業架構，企業自己的資料中心與本地桌上型電腦之外的資訊科技資源，只要有網際網路，員工可任何地方存取虛擬伺服器、儲存裝置、串流視訊、特製軟體或各種雲端服務？","options":{"A":"開放資料","B":"社群運算","C":"行動運算","D":"雲端運算"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"雲端運算讓企業將資訊科技資源放在自有資料中心與本地電腦之外，員工只要透過網際網路即可隨處存取虛擬伺服器、儲存、軟體等服務，正符合題幹描述。開放資料是政府資料公開政策，社群運算與行動運算則分別著重社群互動與行動裝置存取，皆非此種資源架構。","concept":"雲端運算","aiExplained":true},{"id":"web-b2-145","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"下列何者為帶領分析公司的業務策略，定義出支援業務策略的資訊通訊科技架構，並建立出一套達成目標架構的路線藍圖？","options":{"A":"CEO","B":"軟體工程師","C":"系統分析師","D":"企業架構師"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"企業架構師（Enterprise Architect）的職責是從企業業務策略出發，規劃能支援該策略的資訊通訊科技（ICT）整體架構，並訂出達成目標架構的路線藍圖。CEO 負責整體經營決策而非 ICT 架構設計，軟體工程師負責開發實作，系統分析師則聚焦單一系統的需求分析，層級與範圍都不同。","concept":"企業架構師職能","aiExplained":true},{"id":"web-b2-146","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"下列何者為從母資料庫提取資訊，然後轉化、清理資料使用它符合運用的資料定義？","options":{"A":"資料倉儲","B":"關聯式資料庫","C":"記憶體資料庫","D":"資料方塊"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"資料倉儲的建置流程即是從來源（母）資料庫擷取資料，經過轉換與清理（ETL：擷取、轉換、載入），使資料符合統一的定義後集中儲存以供分析。關聯式資料庫與記憶體資料庫是資料儲存技術本身，資料方塊則是多維度分析的呈現結構，都不是描述這種擷取轉換流程的系統。","concept":"資料倉儲與 ETL 流程","aiExplained":true},{"id":"web-b2-147","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"下列何者具備資料描述能力的語言，也是具有高度結構性即可驗證性的語言， 允許使用者自行定義？","options":{"A":"HTML","B":"KMS","C":"XML","D":"Tag"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"XML（可延伸標記語言）允許使用者自行定義標籤來描述資料內容，具有嚴謹的結構且可透過 DTD 或 Schema 驗證文件格式，正符合題幹的資料描述、高結構性與可驗證性。HTML 的標籤是固定的且著重呈現而非描述資料，KMS 是知識管理系統，Tag 只是標籤本身的概念。","concept":"XML 標記語言","aiExplained":true},{"id":"web-b2-148","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"下列何者為依照主記憶體而非次要儲存裝置來儲存資料庫，這樣能極大地提升存取速度？","options":{"A":"RDBMS","B":"資料倉儲","C":"In-memory database","D":"NoSQL"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"記憶體資料庫（In-memory database）將資料主要存放在主記憶體（RAM）而非硬碟等次要儲存裝置，因記憶體存取速度遠高於磁碟，可大幅提升查詢與交易效能。RDBMS、資料倉儲與 NoSQL 都是以磁碟為主要儲存媒介的資料庫或儲存架構類型。","concept":"記憶體資料庫（In-memory DB）","aiExplained":true},{"id":"web-b2-149","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"下列何者為一個中央化的資料儲存庫，儲存著從多個資料來源擷取而來的資訊，可以做為資料分析、情報收集和策略規劃等用途？","options":{"A":"資料探勘","B":"資料倉儲","C":"NoSQL","D":"主資料管理"},"answer":"B","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"資料倉儲是集中式的資料儲存庫，整合來自多個異質來源的資料，專供分析、商業情報與策略規劃使用，正符合題幹描述。資料探勘是在資料中挖掘樣式的「分析技術」而非儲存庫，NoSQL 是資料庫類型，主資料管理則是維護主檔資料一致性的治理作法。","concept":"資料倉儲","aiExplained":true},{"id":"web-b2-150","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"在一個企業資訊系統開發專案管理實務中，專案經理經常使用下列哪項管理工具來記錄專案計劃與控制時程？","options":{"A":"折線圖","B":"雷達圖","C":"甘特圖","D":"K 線圖"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"甘特圖以橫條呈現各項工作任務的起訖時間與進度，是專案經理記錄專案計畫、追蹤與控制時程最常用的工具。折線圖與雷達圖用於一般數據趨勢或多指標比較，K 線圖則用於股價走勢分析，皆非專案時程管理工具。","concept":"甘特圖與專案時程管理","aiExplained":true},{"id":"web-b2-151","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"物聯網可以說是一種結合分散式運算、行動運算、感測網路、人工智慧與人機界面的一個科技平台，主要結構可分為三個層級，分別為感測器層、網路層以及分析層。在物聯網中常使用的射頻識別（RFID）晶片應該被歸類為哪一層？","options":{"A":"感測器層","B":"網路層","C":"分析層","D":"應用層"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"RFID 晶片貼附在物品上，負責感測與識別物品身分並供讀取器蒐集資料，屬於物聯網最底層的感測器層（感知層）。網路層負責資料的傳輸，分析層負責資料的處理與應用決策，RFID 本身不承擔這些功能。","concept":"物聯網三層架構","aiExplained":true},{"id":"web-b2-152","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"每個專案都有基本條件限制著，下列哪一個選項，其中任何一個因素變了，其它也會被影響？","options":{"A":"成本、時間、流程","B":"時間、流程、範疇","C":"流程、時間、人力","D":"成本、時間、範疇"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"專案管理的三重限制（鐵三角）是成本、時間與範疇：任一因素改變都會牽動另外兩者，例如擴大範疇通常需要更多時間或成本。其餘選項中的「流程」「人力」並非三重限制的構成要素，故 D 正確。","concept":"專案三重限制（鐵三角）","aiExplained":true},{"id":"web-b2-153","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"下列何者為專案管理的功能在不受控制且常常未考慮到對預算及時程衝擊下被隨意增添？","options":{"A":"範圍蔓延","B":"交付標的","C":"甘特圖","D":"關鍵路徑"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"範圍蔓延（Scope Creep）指專案的功能或需求在缺乏變更控制下不斷被隨意加入，且未評估對預算與時程的衝擊，是專案失控的常見原因。交付標的為專案應產出的成果，甘特圖與關鍵路徑則是時程管理工具與技術，皆與題幹描述無關。","concept":"範圍蔓延（Scope Creep）","aiExplained":true},{"id":"web-b2-154","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"下列何者指企業逐漸可接受私人擁有裝置，太多員工想把他們的智慧型手機連上公司系統，目前正在發展實用的政策？","options":{"A":"員工自攜設備","B":"資助模型","C":"專案管理","D":"專案投資組合"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"員工自攜設備（BYOD, Bring Your Own Device）指企業允許員工以私人的智慧型手機、平板等裝置連上公司系統工作，並為此制定安全與管理政策，正符合題幹描述。資助模型、專案管理與專案投資組合都與員工私人裝置接入公司系統的議題無關。","concept":"BYOD（員工自攜設備）","aiExplained":true},{"id":"web-b2-155","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"下列何者為一種應用在標籤上的科技，包括一個具有微處理的小晶片，再加上一個能接收與傳輸資料的小型天線？","options":{"A":"虛擬實境","B":"Optical Character Recognition（OCR）","C":"4G","D":"Radio Frequency IDentification（RFID）"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"RFID（無線射頻識別）標籤由一顆內含微處理功能的晶片與一組可接收、傳輸無線電訊號的小型天線組成，常貼附於物品上做自動識別與追蹤。虛擬實境是沉浸式顯示技術，OCR 是光學文字辨識，4G 是行動通訊標準，均與標籤上的晶片天線結構無關。","concept":"RFID 技術","aiExplained":true},{"id":"web-b2-156","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"下列何者為適合儲存與分析大數據的資料庫管理系統？","options":{"A":"Relational Database Management System（RDBMS）","B":"Data Cubes","C":"NoSQL","D":"In-memory database"},"answer":"C","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"NoSQL 資料庫不受固定資料表結構限制，能水平擴充處理大量、多樣且快速累積的非結構化資料，因此最適合大數據的儲存與分析。RDBMS 依賴固定綱要，難以應付非結構化巨量資料；Data Cubes 是多維分析結構；記憶體資料庫著重速度但受記憶體容量限制。","concept":"NoSQL 與大數據儲存","aiExplained":true},{"id":"web-b2-157","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"下列何者為一種資料集合，其數量龐大，其內容多變、累積的速度迅速，以至於我們難以用傳統方法儲存、分析它？","options":{"A":"大數據","B":"資料挖掘","C":"無疆界資料庫","D":"資料科學家"},"answer":"A","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"題幹描述的正是大數據的 3V 特徵：數量龐大（Volume）、內容多變（Variety）、累積速度快（Velocity），以致傳統資料庫工具難以儲存與分析。資料挖掘是分析技術而非資料集合，資料科學家是職務角色，皆不符合「資料集合」的描述。","concept":"大數據 3V 特徵","aiExplained":true},{"id":"web-b2-158","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"Davenport and Short 提出企業流程再造實施的五個步驟，包括1.了解現行流程；2.確定需要重新設計的流程；3.建立新流程的雛型；4.確定資訊科技的功用；5.建立企業願景及活動目的。請問正確的順序應該為？","options":{"A":"12345","B":"52143","C":"13524","D":"53241"},"answer":"B","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"Davenport 與 Short 的企業流程再造五步驟依序為：先建立企業願景與活動目的（5），再確定需要重新設計的流程（2），接著了解並衡量現行流程（1），然後確定資訊科技的功用（4），最後建立新流程的雛型（3），即 52143。此順序反映先有策略願景、再選定標的、理解現況、導入 IT、最後打造雛型驗證的邏輯。","concept":"企業流程再造（BPR）步驟","aiExplained":true},{"id":"web-b2-159","subject":"B2","subjectName":"經營管理數位化概論","topic":"b2-c2","stem":"某運輸公司利用儲存於資料庫中關於客戶需求、可用於駕駛員、車輛、貨物重量的資料找出數以千計規則，並以此推理規劃出最佳路線以及駕駛員、車輛和貨物指派，這樣的系統技術屬於？","options":{"A":"作業系統","B":"ERP 系統","C":"資料庫系統","D":"專家系統"},"answer":"D","needsContext":false,"source":"官方學習指引練習題（華筑版）","srcUrl":"https://www.ipas.org.tw/api/proxy/uploads/certification_resource/b38bd86260a546a3aa41289eea23c765/1128%EF%BC%88%E8%8F%AF%E7%AD%91%EF%BC%89%E8%80%83%E7%A7%912_%E7%B6%93%E7%87%9F%E7%AE%A1%E7%90%86%E6%95%B8%E4%BD%8D%E5%8C%96%E6%A6%82%E8%AB%96_20251212131032.pdf","explanation":"專家系統以知識庫中數以千計的規則（if-then）進行推理，模擬專家決策，題幹中依規則推理出最佳路線與人車貨指派正是典型應用。作業系統管理電腦資源，ERP 整合企業營運流程，資料庫系統只負責資料的儲存與查詢，都不具備規則推理能力。","concept":"專家系統與規則推理","aiExplained":true}];
